    81→func (s *scanner) rescan(ctx context.Context, library string, fullRescan bool) error {
    82→	folderScanner := s.folders[library]
    83→	start := time.Now()
    84→
    85→	lib, ok := s.libs[library]
    86→	if !ok {
    87→		log.Error(ctx, "Folder not a valid library path", "folder", library)
    88→		return fmt.Errorf("folder %s not a valid library path", library)
    89→	}
    90→
    91→	s.setStatusStart(library)
    92→	defer s.setStatusEnd(library, start)
    93→
    94→	if fullRescan {
    95→		log.Debug("Scanning folder (full scan)", "folder", library)
    96→	} else {
    97→		log.Debug("Scanning folder", "folder", library, "lastScan", lib.LastScanAt)
    98→	}
    99→
   100→	progress, cancel := s.startProgressTracker(library)
   101→	defer cancel()
   102→
   103→	changeCount, err := folderScanner.Scan(ctx, lib, fullRescan, progress)
   104→	if err != nil {
   105→		log.Error("Error scanning Library", "folder", library, err)
   106→	}
   107→
   108→	if changeCount > 0 {
   109→		log.Debug(ctx, "Detected changes in the music folder. Sending refresh event",
   110→			"folder", library, "changeCount", changeCount)
   111→		// Don't use real context, forcing a refresh in all open windows, including the one that triggered the scan
   112→		s.broker.SendMessage(context.Background(), &events.RefreshResource{})
   113→	}
   114→
   115→	s.updateLastModifiedSince(ctx, library, start)
   116→	return err
   117→}
   118→
   119→func (s *scanner) startProgressTracker(library string) (chan uint32, context.CancelFunc) {
   120→	// Must be a new context (not the one passed to the scan method) to allow broadcasting the scan status to all clients
   121→	ctx, cancel := context.WithCancel(context.Background())
   122→	progress := make(chan uint32, 1000)
   123→	limiter := rate.Sometimes{Interval: conf.Server.DevActivityPanelUpdateRate}
   124→	go func() {
   125→		s.broker.SendMessage(ctx, &events.ScanStatus{Scanning: true, Count: 0, FolderCount: 0})
   126→		defer func() {
   127→			if status, ok := s.getStatus(library); ok {
   128→				s.broker.SendMessage(ctx, &events.ScanStatus{
   129→					Scanning:    false,
   130→					Count:       int64(status.fileCount),
   131→					FolderCount: int64(status.folderCount),
   132→				})
   133→			}
   134→		}()
   135→		for {
   136→			select {
   137→			case <-ctx.Done():
   138→				return
   139→			case count := <-progress:
   140→				if count == 0 {
   141→					continue
   142→				}
   143→				totalFolders, totalFiles := s.incStatusCounter(library, count)
   144→				limiter.Do(func() {
   145→					s.broker.SendMessage(ctx, &events.ScanStatus{
   146→						Scanning:    true,
   147→						Count:       int64(totalFiles),
   148→						FolderCount: int64(totalFolders),
   149→					})
   150→				})
   151→			}
   152→		}
   153→	}()
   154→	return progress, cancel
   155→}
   156→
   157→func (s *scanner) getStatus(folder string) (scanStatus, bool) {
   158→	s.lock.RLock()
   159→	defer s.lock.RUnlock()
   160→	status, ok := s.status[folder]
   161→	return *status, ok
   162→}
   163→
   164→func (s *scanner) incStatusCounter(folder string, numFiles uint32) (totalFolders uint32, totalFiles uint32) {
   165→	s.lock.Lock()
   166→	defer s.lock.Unlock()
   167→	if status, ok := s.status[folder]; ok {
   168→		status.fileCount += numFiles
   169→		status.folderCount++
   170→		totalFolders = status.folderCount
   171→		totalFiles = status.fileCount
   172→	}
   173→	return
   174→}
   175→
   176→func (s *scanner) setStatusStart(folder string) {
   177→	s.lock.Lock()
   178→	defer s.lock.Unlock()
   179→	if status, ok := s.status[folder]; ok {
   180→		status.active = true
   181→		status.fileCount = 0
   182→		status.folderCount = 0
   183→	}
   184→}
   185→
   186→func (s *scanner) setStatusEnd(folder string, lastUpdate time.Time) {
   187→	s.lock.Lock()
   188→	defer s.lock.Unlock()
   189→	if status, ok := s.status[folder]; ok {
   190→		status.active = false
   191→		status.lastUpdate = lastUpdate
   192→	}
   193→}
   194→
   195→func (s *scanner) RescanAll(ctx context.Context, fullRescan bool) error {
   196→	ctx = context.WithoutCancel(ctx)
   197→	s.once.Do(s.loadFolders)
   198→
   199→	if !isScanning.TryLock() {
   200→		log.Debug(ctx, "Scanner already running, ignoring request for rescan.")
   201→		return ErrAlreadyScanning
   202→	}
   203→	defer isScanning.Unlock()
   204→
   205→	var hasError bool
   206→	for folder := range s.folders {
   207→		err := s.rescan(ctx, folder, fullRescan)
   208→		hasError = hasError || err != nil
   209→	}
   210→	if hasError {
   211→		log.Error(ctx, "Errors while scanning media. Please check the logs")
   212→		core.WriteAfterScanMetrics(ctx, s.ds, false)
   213→		return ErrScanError
   214→	}
   215→	core.WriteAfterScanMetrics(ctx, s.ds, true)
   216→	return nil
   217→}
   218→
   219→func (s *scanner) Status(library string) (*StatusInfo, error) {
   220→	s.once.Do(s.loadFolders)
   221→	status, ok := s.getStatus(library)
   222→	if !ok {
   223→		return nil, errors.New("library not found")
   224→	}
   225→	return &StatusInfo{
   226→		Library:     library,
   227→		Scanning:    status.active,
   228→		LastScan:    status.lastUpdate,
   229→		Count:       status.fileCount,
   230→		FolderCount: status.folderCount,
   231→	}, nil
   232→}
   233→
   234→func (s *scanner) updateLastModifiedSince(ctx context.Context, folder string, t time.Time) {
   235→	lib := s.libs[folder]
   236→	id := lib.ID
   237→	if err := s.ds.Library(ctx).UpdateLastScan(id, t); err != nil {
   238→		log.Error("Error updating DB after scan", err)
   239→	}
   240→	lib.LastScanAt = t
   241→	s.libs[folder] = lib
   242→}
   243→
   244→func (s *scanner) loadFolders() {
   245→	ctx := context.TODO()
   246→	libs, _ := s.ds.Library(ctx).GetAll()
   247→	for _, lib := range libs {
   248→		log.Info("Configuring Media Folder", "name", lib.Name, "path", lib.Path)
   249→		s.folders[lib.Path] = s.newScanner()
   250→		s.libs[lib.Path] = lib
   251→		s.status[lib.Path] = &scanStatus{
   252→			active:      false,
   253→			fileCount:   0,
   254→			folderCount: 0,
   255→			lastUpdate:  lib.LastScanAt,
   256→		}
   257→	}
   258→}
