   243→func (s *TagScanner) processDeletedDir(ctx context.Context, refresher *refresher, dir string) error {
   244→	start := time.Now()
   245→
   246→	mfs, err := s.ds.MediaFile(ctx).FindAllByPath(dir)
   247→	if err != nil {
   248→		return err
   249→	}
   250→
   251→	c, err := s.ds.MediaFile(ctx).DeleteByPath(dir)
   252→	if err != nil {
   253→		return err
   254→	}
   255→	s.cnt.deleted += c
   256→
   257→	for _, t := range mfs {
   258→		refresher.accumulate(t)
   259→	}
   260→
   261→	err = refresher.flush(ctx)
   262→	log.Info(ctx, "Finished processing deleted folder", "dir", dir, "purged", len(mfs), "elapsed", time.Since(start))
   263→	return err
   264→}
   265→
   266→func (s *TagScanner) processChangedDir(ctx context.Context, refresher *refresher, fullScan bool, dir string) error {
   267→	start := time.Now()
   268→
   269→	// Load folder's current tracks from DB into a map
   270→	currentTracks := map[string]model.MediaFile{}
   271→	ct, err := s.ds.MediaFile(ctx).FindAllByPath(dir)
   272→	if err != nil {
   273→		return err
   274→	}
   275→	for _, t := range ct {
   276→		currentTracks[t.Path] = t
   277→	}
   278→
   279→	// Load track list from the folder
   280→	files, err := loadAllAudioFiles(dir)
   281→	if err != nil {
   282→		return err
   283→	}
   284→
   285→	// If no files to process, return
   286→	if len(files)+len(currentTracks) == 0 {
   287→		return nil
   288→	}
   289→
   290→	orphanTracks := map[string]model.MediaFile{}
   291→	for k, v := range currentTracks {
   292→		orphanTracks[k] = v
   293→	}
   294→
   295→	// If track from folder is newer than the one in DB, select for update/insert in DB
   296→	log.Trace(ctx, "Processing changed folder", "dir", dir, "tracksInDB", len(currentTracks), "tracksInFolder", len(files))
   297→	var filesToUpdate []string
   298→	for filePath, entry := range files {
   299→		c, inDB := currentTracks[filePath]
   300→		if !inDB || fullScan {
   301→			filesToUpdate = append(filesToUpdate, filePath)
   302→			s.cnt.added++
   303→		} else {
   304→			info, err := entry.Info()
   305→			if err != nil {
   306→				log.Error("Could not stat file", "filePath", filePath, err)
   307→				continue
   308→			}
   309→			if info.ModTime().After(c.UpdatedAt) {
   310→				filesToUpdate = append(filesToUpdate, filePath)
   311→				s.cnt.updated++
   312→			}
   313→		}
   314→
   315→		// Force a refresh of the album and artist, to cater for cover art files
   316→		refresher.accumulate(c)
   317→
   318→		// Only leaves in orphanTracks the ones not found in the folder. After this loop any remaining orphanTracks
   319→		// are considered gone from the music folder and will be deleted from DB
   320→		delete(orphanTracks, filePath)
   321→	}
   322→
   323→	numUpdatedTracks := 0
   324→	numPurgedTracks := 0
   325→
   326→	if len(filesToUpdate) > 0 {
   327→		numUpdatedTracks, err = s.addOrUpdateTracksInDB(ctx, refresher, dir, currentTracks, filesToUpdate)
   328→		if err != nil {
   329→			return err
   330→		}
   331→	}
   332→
   333→	if len(orphanTracks) > 0 {
   334→		numPurgedTracks, err = s.deleteOrphanSongs(ctx, refresher, dir, orphanTracks)
   335→		if err != nil {
   336→			return err
   337→		}
   338→	}
   339→
   340→	err = refresher.flush(ctx)
   341→	log.Info(ctx, "Finished processing changed folder", "dir", dir, "updated", numUpdatedTracks,
   342→		"deleted", numPurgedTracks, "elapsed", time.Since(start))
   343→	return err
   344→}
   345→
   346→func (s *TagScanner) deleteOrphanSongs(
   347→	ctx context.Context,
   348→	refresher *refresher,
   349→	dir string,
   350→	tracksToDelete map[string]model.MediaFile,
   351→) (int, error) {
   352→	numPurgedTracks := 0
   353→
   354→	log.Debug(ctx, "Deleting orphan tracks from DB", "dir", dir, "numTracks", len(tracksToDelete))
   355→	// Remaining tracks from DB that are not in the folder are deleted
   356→	for _, ct := range tracksToDelete {
   357→		numPurgedTracks++
   358→		refresher.accumulate(ct)
   359→		if err := s.ds.MediaFile(ctx).Delete(ct.ID); err != nil {
   360→			return 0, err
   361→		}
   362→		s.cnt.deleted++
   363→	}
   364→	return numPurgedTracks, nil
   365→}
   366→
   367→func (s *TagScanner) addOrUpdateTracksInDB(
   368→	ctx context.Context,
   369→	refresher *refresher,
   370→	dir string,
   371→	currentTracks map[string]model.MediaFile,
   372→	filesToUpdate []string,
   373→) (int, error) {
   374→	log.Trace(ctx, "Updating mediaFiles in DB", "dir", dir, "numFiles", len(filesToUpdate))
   375→
   376→	numUpdatedTracks := 0
