		if !filepath.IsAbs(filePath) {
			t.Errorf("Expected absolute path, got: %s", filePath)
		}
	}
}

// TestIntegrationMetadataExtraction tests that metadata is correctly extracted from audio files
func TestIntegrationMetadataExtraction(t *testing.T) {
	ctx := context.Background()

	// Use real fixture files
	fixtureFile := "tests/fixtures/test.mp3"

	// Check if fixture exists
	if _, err := os.Stat(fixtureFile); err != nil {
		t.Skipf("Test fixture not found: %s", fixtureFile)
	}

	// Extract metadata from the fixture file
	tags, err := metadata.Extract(fixtureFile)
	if err != nil {
		t.Fatalf("metadata.Extract failed: %v", err)
	}

	if len(tags) == 0 {
		t.Fatal("Expected metadata to be extracted, got empty map")
	}

	// Verify basic metadata fields are accessible
	for filePath, tag := range tags {
		if tag.FilePath() != filePath {
			t.Errorf("FilePath mismatch: expected %s, got %s", filePath, tag.FilePath())
		}

		// Verify we can access common metadata
		_ = tag.Title()
		_ = tag.Artist()
		_ = tag.Album()
		_ = tag.TrackNumber()
		year, _ := tag.Date()
		_ = year

		// Size and duration should be present for valid audio files
		if tag.Size() == 0 {
			t.Errorf("Expected non-zero file size for %s", filePath)
		}
	}
}

// TestIntegrationMediaFileMapping tests that metadata is correctly mapped to MediaFile objects
func TestIntegrationMediaFileMapping(t *testing.T) {
	ctx := context.Background()

	fixtureFile := "tests/fixtures/test.mp3"
	if _, err := os.Stat(fixtureFile); err != nil {
		t.Skipf("Test fixture not found: %s", fixtureFile)
	}

	// Extract metadata
	tags, err := metadata.Extract(fixtureFile)
	if err != nil {
		t.Fatalf("metadata.Extract failed: %v", err)
	}

	if len(tags) == 0 {
		t.Fatal("No metadata extracted")
	}

	// Create mapper
	genreRepo := &tests.MockedGenreRepo{}
	mapper := NewMediaFileMapper("/music", genreRepo)

	// Map metadata to MediaFile
	for _, tag := range tags {
		mf := mapper.ToMediaFile(tag)

		// Verify required fields are set
		if mf.ID == "" {
			t.Error("MediaFile ID is empty")
		}
		if mf.Path == "" {
			t.Error("MediaFile Path is empty")
		}
		if mf.Suffix == "" {
			t.Error("MediaFile Suffix is empty")
		}

		// Verify audio properties are extracted
		if mf.Duration == 0 {
			t.Errorf("MediaFile Duration is 0 for %s", mf.Path)
		}

		// Verify title is set (fallback to filename if not in tags)
		if mf.Title == "" {
			t.Errorf("MediaFile Title is empty for %s", mf.Path)
		}

		// Verify timestamps are set
		if mf.CreatedAt.IsZero() {
			t.Error("MediaFile CreatedAt is zero")
		}
		if mf.UpdatedAt.IsZero() {
			t.Error("MediaFile UpdatedAt is zero")
		}
	}
}

// TestIntegrationFullScan tests the complete scanning pipeline with database persistence
func TestIntegrationFullScan(t *testing.T) {
	ctx := context.Background()
	tempDir := t.TempDir()

	// Create test directory structure
	subDir := filepath.Join(tempDir, "artist", "album")
	if err := os.MkdirAll(subDir, 0o755); err != nil {
		t.Fatalf("Failed to create temp directory: %v", err)
	}

	// Copy fixture file
	srcFile := "tests/fixtures/test.mp3"
	if _, err := os.Stat(srcFile); err != nil {
		t.Skipf("Test fixture not found: %s", srcFile)
	}

	src, _ := os.Open(srcFile)
	defer src.Close()

	destFile := filepath.Join(subDir, "test.mp3")
	dst, _ := os.Create(destFile)
	defer dst.Close()
	src.WriteTo(dst)
	dst.Close()

	// Setup mock datastore
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedAlbum = albumRepo
	ds.MockedArtist = artistRepo

	// Create library
	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       tempDir,
		LastScanAt: time.Time{},
		CreatedAt:  time.Now(),
		UpdatedAt:  time.Now(),
	}

	// Create scanner and perform scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)

	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// Verify changes were detected
	if changeCount == 0 {
		t.Fatal("Expected scan to detect changes, got 0")
	}

	// Verify media files were added to database
	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) == 0 {
		t.Fatal("Expected media files to be saved to database, got 0")
	}

	// Verify metadata was correctly mapped
	mf := mediaFiles[0]
	if mf.Path != destFile {
		t.Errorf("Expected path %s, got %s", destFile, mf.Path)
	}
	if mf.Suffix != "mp3" {
		t.Errorf("Expected suffix 'mp3', got '%s'", mf.Suffix)
	}
	if mf.Duration == 0 {
		t.Error("Expected non-zero duration")
	}
	if mf.Title == "" {
		t.Error("Expected title to be set")
	}
}

// TestIntegrationIncrementalScan tests that re-scanning without changes produces no updates
func TestIntegrationIncrementalScan(t *testing.T) {
	ctx := context.Background()
	tempDir := t.TempDir()

	// Create test directory structure
	subDir := filepath.Join(tempDir, "artist", "album")
	if err := os.MkdirAll(subDir, 0o755); err != nil {
		t.Fatalf("Failed to create temp directory: %v", err)
	}

	// Copy fixture file
	srcFile := "tests/fixtures/test.mp3"
	if _, err := os.Stat(srcFile); err != nil {
		t.Skipf("Test fixture not found: %s", srcFile)
	}

	src, _ := os.Open(srcFile)
	defer src.Close()

	destFile := filepath.Join(subDir, "test.mp3")
	dst, _ := os.Create(destFile)
	defer dst.Close()
	src.WriteTo(dst)
	dst.Close()

	// Setup mock datastore
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedAlbum = albumRepo
	ds.MockedArtist = artistRepo

	// Create library with LastScanAt set to future (no changes detected)
	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       tempDir,
		LastScanAt: time.Now().Add(10 * time.Hour),
		CreatedAt:  time.Now(),
		UpdatedAt:  time.Now(),
	}

	// First scan - full scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)

	changeCount1, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("First scan failed: %v", err)
	}

	initialFileCount := len(mediaFileRepo.data)
	if initialFileCount == 0 {
		t.Fatal("Expected files to be in database after first scan")
	}

	// Second scan - with LastScanAt in the future
	scanner2 := NewTagScanner(ds, nil, nil)
	progress2 := make(chan uint32, 100)

	changeCount2, err := scanner2.Scan(ctx, lib, false, progress2)
	close(progress2)

	if err != nil {
		t.Fatalf("Second scan failed: %v", err)
	}

	// Verify no changes were detected when file hasn't been modified
	if changeCount2 != 0 {
		t.Errorf("Expected no changes on incremental scan, got %d", changeCount2)
	}

	// Verify file count remains the same
	if len(mediaFileRepo.data) != initialFileCount {
		t.Errorf("Expected %d files, got %d", initialFileCount, len(mediaFileRepo.data))
	}
}

