// TestIntegrationMediaFileMapping tests that metadata is correctly mapped to MediaFile objects
func TestIntegrationMediaFileMapping(t *testing.T) {
	ctx := context.Background()

	fixtureFile := "tests/fixtures/test.mp3"
	if _, err := os.Stat(fixtureFile); err != nil {
		t.Skipf("Test fixture not found: %s", fixtureFile)
	}

	// Extract metadata
	tags, err := metadata.Extract(fixtureFile)
	if err != nil {
		t.Fatalf("metadata.Extract failed: %v", err)
	}

	if len(tags) == 0 {
		t.Fatal("No metadata extracted")
	}

	// Create mapper
	genreRepo := &tests.MockedGenreRepo{}
	mapper := NewMediaFileMapper("/music", genreRepo)

	// Map metadata to MediaFile
	for _, tag := range tags {
		mf := mapper.ToMediaFile(tag)

		// Verify required fields are set
		if mf.ID == "" {
			t.Error("MediaFile ID is empty")
		}
		if mf.Path == "" {
			t.Error("MediaFile Path is empty")
		}
		if mf.Suffix == "" {
			t.Error("MediaFile Suffix is empty")
		}

		// Verify audio properties are extracted
		if mf.Duration == 0 {
			t.Errorf("MediaFile Duration is 0 for %s", mf.Path)
		}

		// Verify title is set (fallback to filename if not in tags)
		if mf.Title == "" {
			t.Errorf("MediaFile Title is empty for %s", mf.Path)
		}

		// Verify timestamps are set
		if mf.CreatedAt.IsZero() {
			t.Error("MediaFile CreatedAt is zero")
		}
		if mf.UpdatedAt.IsZero() {
			t.Error("MediaFile UpdatedAt is zero")
		}
	}
}

